You can perform several operations at the same time by using the bulk() method of the client. The operations may be of the same type or of different types. Note that the operations must be separated by a 
 and the entire string must be a single line: . movies = '{ "index" : { "_index" : "my-dsl-index", "_id" : "2" } } 
 { "title" : "Interstellar", "director" : "Christopher Nolan", "year" : "2014"} 
 { "create" : { "_index" : "my-dsl-index", "_id" : "3" } } 
 { "title" : "Star Trek Beyond", "director" : "Justin Lin", "year" : "2015"} 
 { "update" : {"_id" : "3", "_index" : "my-dsl-index" } } 
 { "doc" : {"year" : "2016"} }' client.bulk(movies) . copy .

